     1|/**
     2| * IVX Capital Deployment Platform — Investor CRM durable store (owner-only).
     3| *
     4| * BLOCK 20. The first pillar of turning IVX from an Opportunity Intelligence
     5| * platform into a Capital Deployment Platform: a real, owner-managed CRM of
     6| * investor records that the owner can create, read, update, and delete.
     7| *
     8| * HARD HONESTY RULE (the platform-wide rule, enforced here):
     9| *   - IVX NEVER fabricates investors, emails, phone numbers, companies, or deal
    10| *     data. Every record originates from a real, attributable source:
    11| *       owner_entered | submitted_form | crm_import | public_source | verified_deal
    12| *     `source` is required on create; `sourceDetail` carries the attribution
    13| *     (who entered it / which form / which import file / which public URL).
    14| *   - Unknown values stay empty/null — never invented.
    15| *   - Lead/relationship scores are owner-supplied judgements (0–100), not
    16| *     auto-fabricated; they default to 0 until the owner sets them.
    17| *
    18| * Durable layout (mirrors the proven ivx-capital-network-store pattern):
    19| *   logs/audit/investor-crm/investors.jsonl  append-only event log
    20| *   logs/audit/investor-crm/investors.json   materialised current state
    21| *
    22| * Runtime-light + deterministic: only filesystem I/O, no AI/network. Fully testable.
    23| */
    24|import { appendFile, mkdir, readFile, writeFile } from 'node:fs/promises';
    25|import path from 'node:path';
    26|import { auditDir } from './ivx-data-root';
    27|import {
    28|  isDurableStoreConfigured,
    29|  readDurableJson,
    30|  writeDurableJson,
    31|  appendDurableEvent,
    32|} from './ivx-durable-store';
    33|import { resolveCanonicalIdentity } from './ivx-crm-canonical';
    34|
    35|export const IVX_INVESTOR_CRM_MARKER = 'ivx-investor-crm-2026-05-31';
    36|
    37|/** Where an investor record came from — required, for honest attribution. */
    38|export type InvestorSource =
    39|  | 'owner_entered'
    40|  | 'submitted_form'
    41|  | 'crm_import'
    42|  | 'public_source'
    43|  | 'verified_deal';
    44|
    45|/** Relationship lifecycle stage. */
    46|export type InvestorStatus =
    47|  | 'prospect'
    48|  | 'contacted'
    49|  | 'meeting_scheduled'
    50|  | 'active'
    51|  | 'invested';
    52|
    53|/** Accreditation state — `unknown` until verified, never assumed. */
    54|export type AccreditedStatus = 'accredited' | 'non_accredited' | 'unknown';
    55|
    56|/**
    57| * The kind of capital-relationship this record represents. The Investor CRM is
    58| * the single owner-managed contact store for every party type the owner imports.
    59| */
    60|export type PartyType =
    61|  | 'investor'
    62|  | 'buyer'
    63|  | 'broker'
    64|  | 'developer'
    65|  | 'lender'
    66|  | 'partner';
    67|
    68|export type InvestorRecord = {
    69|  id: string;
    70|  name: string;
    71|  /** Which party type this contact is (investor/buyer/broker/developer/lender/partner). */
    72|  partyType: PartyType;
    73|  company: string;
    74|  email: string;
    75|  phone: string;
    76|  location: string;
    77|  /** e.g. "Family office", "Syndicator", "Private equity", "Individual". */
    78|  investmentType: string;
    79|  accreditedStatus: AccreditedStatus;
    80|  /** Markets the investor prefers (e.g. ["South Florida", "Miami"]). */
    81|  preferredMarkets: string[];
    82|  /** Asset classes (e.g. ["Multifamily", "Luxury condos", "Land"]). */
    83|  preferredAssetClasses: string[];
    84|  /** Free-text typical check size as the owner recorded it (e.g. "$250k–$1M"). */
    85|  typicalCheckSize: string;
    86|  /** Free-text timeline (e.g. "0–6 months", "Opportunistic"). */
    87|  investmentTimeline: string;
    88|  notes: string;
    89|  /** ISO date of the last contact, or null if never contacted. */
    90|  lastContactDate: string | null;
    91|  /** Owner-supplied lead quality, 0–100. */
    92|  leadScore: number;
    93|  /** Owner-supplied relationship strength, 0–100. */
    94|  relationshipScore: number;
    95|  status: InvestorStatus;
    96|  source: InvestorSource;
    97|  /** Attribution detail for the source (who/which form/which import/which URL). */
    98|  sourceDetail: string;
    99|  createdAt: string;
   100|  updatedAt: string;
   101|};
   102|
   103|const CRM_ROOT = auditDir('investor-crm');
   104|const INVESTORS_STATE = path.join(CRM_ROOT, 'investors.json');
   105|
   106|const VALID_SOURCES: ReadonlySet<InvestorSource> = new Set([
   107|  'owner_entered', 'submitted_form', 'crm_import', 'public_source', 'verified_deal',
   108|]);
   109|const VALID_STATUS: ReadonlySet<InvestorStatus> = new Set([
   110|  'prospect', 'contacted', 'meeting_scheduled', 'active', 'invested',
   111|]);
   112|const VALID_ACCREDITED: ReadonlySet<AccreditedStatus> = new Set([
   113|  'accredited', 'non_accredited', 'unknown',
   114|]);
   115|export const VALID_PARTY_TYPES: ReadonlySet<PartyType> = new Set([
   116|  'investor', 'buyer', 'broker', 'developer', 'lender', 'partner',
   117|]);
   118|
   119|/** Normalize any input to a valid PartyType, defaulting to 'investor'. */
   120|export function normalizePartyType(value: unknown): PartyType {
   121|  const v = asTrimmedString(value).toLowerCase() as PartyType;
   122|  return VALID_PARTY_TYPES.has(v) ? v : 'investor';
   123|}
   124|
   125|/**
   126| * Stable dedupe key for a contact: party type + name + the strongest available
   127| * identity signal (email, else phone, else company). Used to detect duplicate
   128| * rows on import so a re-imported list never silently doubles the CRM.
   129| */
   130|export function investorDedupeKey(input: {
   131|  name?: unknown;
   132|  partyType?: unknown;
   133|  email?: unknown;
   134|  phone?: unknown;
   135|  company?: unknown;
   136|}): string {
   137|  const name = asTrimmedString(input.name).toLowerCase();
   138|  const party = normalizePartyType(input.partyType);
   139|  const email = asTrimmedString(input.email).toLowerCase();
   140|  const phone = asTrimmedString(input.phone).replace(/[^0-9+]/g, '');
   141|  const company = asTrimmedString(input.company).toLowerCase();
   142|  const identity = email || phone || company || '';
   143|  return `${party}|${name}|${identity}`;
   144|}
   145|
   146|function nowIso(): string {
   147|  return new Date().toISOString();
   148|}
   149|
   150|function createId(prefix: string): string {
   151|  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
   152|    return `${prefix}-${crypto.randomUUID()}`;
   153|  }
   154|  return `${prefix}-${Date.now()}-${Math.random().toString(16).slice(2)}`;
   155|}
   156|
   157|/** Clamp any input to a 0–100 integer score. */
   158|export function clampScore(value: unknown): number {
   159|  const n = typeof value === 'number' ? value : Number(value);
   160|  if (!Number.isFinite(n)) return 0;
   161|  return Math.max(0, Math.min(100, Math.round(n)));
   162|}
   163|
   164|function asTrimmedString(value: unknown): string {
   165|  return typeof value === 'string' ? value.trim() : '';
   166|}
   167|
   168|function asStringArray(value: unknown): string[] {
   169|  if (!Array.isArray(value)) return [];
   170|  return Array.from(new Set(value.map((v) => asTrimmedString(v)).filter(Boolean)));
   171|}
   172|
   173|function normalizeAccredited(value: unknown): AccreditedStatus {
   174|  const v = asTrimmedString(value).toLowerCase() as AccreditedStatus;
   175|  return VALID_ACCREDITED.has(v) ? v : 'unknown';
   176|}
   177|
   178|/** Normalize an ISO-ish date string to an ISO string, or null if absent/invalid. */
   179|export function normalizeDate(value: unknown): string | null {
   180|  const v = asTrimmedString(value);
   181|  if (!v) return null;
   182|  const time = Date.parse(v);
   183|  if (!Number.isFinite(time)) return null;
   184|  return new Date(time).toISOString();
   185|}
   186|
   187|async function readJsonFile<T>(file: string, fallback: T): Promise<T> {
   188|  if (isDurableStoreConfigured()) {
   189|    return readDurableJson<T>(file, fallback);
   190|  }
   191|  try {
   192|    const raw = await readFile(file, 'utf8');
   193|    return JSON.parse(raw) as T;
   194|  } catch {
   195|    return fallback;
   196|  }
   197|}
   198|
   199|async function writeJsonFile(file: string, value: unknown): Promise<void> {
   200|  if (isDurableStoreConfigured()) {
   201|    await writeDurableJson(file, value);
   202|    return;
   203|  }
   204|  await mkdir(CRM_ROOT, { recursive: true });
   205|  await writeFile(file, JSON.stringify(value, null, 2), 'utf8');
   206|}
   207|
   208|async function appendEvent(event: Record<string, unknown>): Promise<void> {
   209|  const eventFile = path.join(CRM_ROOT, 'investors.jsonl');
   210|  if (isDurableStoreConfigured()) {
   211|    try {
   212|      await appendDurableEvent(eventFile, event);
   213|    } catch {
   214|      // Forensic log is best-effort; never break a CRM write on log failure.
   215|    }
   216|    return;
   217|  }
   218|  try {
   219|    await mkdir(CRM_ROOT, { recursive: true });
   220|    await appendFile(eventFile, `${JSON.stringify(event)}\n`, 'utf8');
   221|  } catch {
   222|    // Forensic log is best-effort; never break a CRM write on log failure.
   223|  }
   224|}
   225|
   226|export type CreateInvestorInput = {
   227|  name: string;
   228|  source: InvestorSource;
   229|  sourceDetail?: string;
   230|  partyType?: PartyType;
   231|  company?: string;
   232|  email?: string;
   233|  phone?: string;
   234|  location?: string;
   235|  investmentType?: string;
   236|  accreditedStatus?: AccreditedStatus;
   237|  preferredMarkets?: string[];
   238|  preferredAssetClasses?: string[];
   239|  typicalCheckSize?: string;
   240|  investmentTimeline?: string;
   241|  notes?: string;
   242|  lastContactDate?: string | null;
   243|  leadScore?: number;
   244|  relationshipScore?: number;
   245|  status?: InvestorStatus;
   246|};
   247|
   248|export type UpdateInvestorInput = Partial<Omit<CreateInvestorInput, 'source'>> & {
   249|  source?: InvestorSource;
   250|};
   251|
   252|/** Validation result for a create input. */
   253|export type InvestorValidation = { ok: true } | { ok: false; error: string };
   254|
   255|/**
   256| * Validate a create input. Enforces the honesty rule: name + a real attributable
   257| * source are required. Everything else is optional (unknowns stay empty).
   258| */
   259|export function validateCreateInvestor(input: CreateInvestorInput): InvestorValidation {
   260|  if (!asTrimmedString(input.name)) {
   261|    return { ok: false, error: 'Investor name is required — IVX never fabricates a record.' };
   262|  }
   263|  if (!VALID_SOURCES.has(input.source)) {
   264|    return {
   265|      ok: false,
   266|      error: 'A real source is required (owner_entered | submitted_form | crm_import | public_source | verified_deal).',
   267|    };
   268|  }
   269|  if ((input.source === 'public_source' || input.source === 'crm_import') && !asTrimmedString(input.sourceDetail)) {
   270|    return {
   271|      ok: false,
   272|      error: 'Source attribution (sourceDetail) is required for public_source and crm_import records.',
   273|    };
   274|  }
   275|  return { ok: true };
   276|}
   277|
   278|function buildRecord(input: CreateInvestorInput, prior?: InvestorRecord): InvestorRecord {
   279|  const status: InvestorStatus = input.status && VALID_STATUS.has(input.status)
   280|    ? input.status
   281|    : prior?.status ?? 'prospect';
   282|  return {
   283|    id: prior?.id ?? createId('investor'),
   284|    name: asTrimmedString(input.name) || prior?.name || '',
   285|    partyType: input.partyType !== undefined ? normalizePartyType(input.partyType) : prior?.partyType ?? 'investor',
   286|    company: input.company !== undefined ? asTrimmedString(input.company) : prior?.company ?? '',
   287|    email: input.email !== undefined ? asTrimmedString(input.email) : prior?.email ?? '',
   288|    phone: input.phone !== undefined ? asTrimmedString(input.phone) : prior?.phone ?? '',
   289|    location: input.location !== undefined ? asTrimmedString(input.location) : prior?.location ?? '',
   290|    investmentType: input.investmentType !== undefined ? asTrimmedString(input.investmentType) : prior?.investmentType ?? '',
   291|    accreditedStatus: input.accreditedStatus !== undefined ? normalizeAccredited(input.accreditedStatus) : prior?.accreditedStatus ?? 'unknown',
   292|    preferredMarkets: input.preferredMarkets !== undefined ? asStringArray(input.preferredMarkets) : prior?.preferredMarkets ?? [],
   293|    preferredAssetClasses: input.preferredAssetClasses !== undefined ? asStringArray(input.preferredAssetClasses) : prior?.preferredAssetClasses ?? [],
   294|    typicalCheckSize: input.typicalCheckSize !== undefined ? asTrimmedString(input.typicalCheckSize) : prior?.typicalCheckSize ?? '',
   295|    investmentTimeline: input.investmentTimeline !== undefined ? asTrimmedString(input.investmentTimeline) : prior?.investmentTimeline ?? '',
   296|    notes: input.notes !== undefined ? asTrimmedString(input.notes) : prior?.notes ?? '',
   297|    lastContactDate: input.lastContactDate !== undefined ? normalizeDate(input.lastContactDate) : prior?.lastContactDate ?? null,
   298|    leadScore: input.leadScore !== undefined ? clampScore(input.leadScore) : prior?.leadScore ?? 0,
   299|    relationshipScore: input.relationshipScore !== undefined ? clampScore(input.relationshipScore) : prior?.relationshipScore ?? 0,
   300|    status,
   301|    source: input.source && VALID_SOURCES.has(input.source) ? input.source : prior?.source ?? 'owner_entered',
   302|    sourceDetail: input.sourceDetail !== undefined ? asTrimmedString(input.sourceDetail) : prior?.sourceDetail ?? '',
   303|    createdAt: prior?.createdAt ?? nowIso(),
   304|    updatedAt: nowIso(),
   305|  };
   306|}
