   308|export async function listInvestors(): Promise<InvestorRecord[]> {
   309|  const items = await readJsonFile<InvestorRecord[]>(INVESTORS_STATE, []);
   310|  return [...items].sort((a, b) => b.updatedAt.localeCompare(a.updatedAt));
   311|}
   312|
   313|export async function getInvestor(id: string): Promise<InvestorRecord | null> {
   314|  const items = await readJsonFile<InvestorRecord[]>(INVESTORS_STATE, []);
   315|  return items.find((item) => item.id === id) ?? null;
   316|}
   317|
   318|/** Canonical company id for a record/input, scoped by party type. */
   319|export function canonicalCompanyIdFor(input: {
   320|  name?: unknown; company?: unknown; email?: unknown; phone?: unknown;
   321|  notes?: unknown; sourceDetail?: unknown; partyType?: unknown;
   322|}): string {
   323|  return resolveCanonicalIdentity({
   324|    name: asTrimmedString(input.name),
   325|    company: asTrimmedString(input.company),
   326|    email: asTrimmedString(input.email),
   327|    phone: asTrimmedString(input.phone),
   328|    notes: asTrimmedString(input.notes),
   329|    sourceDetail: asTrimmedString(input.sourceDetail),
   330|    partyType: input.partyType !== undefined ? normalizePartyType(input.partyType) : 'investor',
   331|  }).canonicalCompanyId;
   332|}
   333|
   334|/**
   335| * Create a new investor record OR update the existing canonical match.
   336| *
   337| * HARD DUPLICATE BLOCKER: before inserting, the record's `canonicalCompanyId`
   338| * (cik → website → domain → legal_name → normalized_name, scoped by party type)
   339| * is checked against the store. If a record with the same canonical id already
   340| * exists, it is UPDATED in place (never a second INSERT), guaranteeing
   341| * one company = one CRM record per party type.
   342| */
   343|export async function createInvestor(
   344|  input: CreateInvestorInput,
   345|): Promise<{ ok: true; investor: InvestorRecord; deduped: boolean } | { ok: false; error: string }> {
   346|  const validation = validateCreateInvestor(input);
   347|  if (!validation.ok) return validation;
   348|  const items = await readJsonFile<InvestorRecord[]>(INVESTORS_STATE, []);
   349|  const canonical = canonicalCompanyIdFor(input);
   350|  const existingIndex = items.findIndex((r) => canonicalCompanyIdFor(r) === canonical);
   351|  if (existingIndex !== -1) {
   352|    const prior = items[existingIndex]!;
   353|    const merged = buildRecord({ ...prior, ...input, name: input.name || prior.name, source: prior.source }, prior);
   354|    items[existingIndex] = merged;
   355|    await writeJsonFile(INVESTORS_STATE, items);
   356|    await appendEvent({ type: 'upsert', investorId: merged.id, canonical, investor: merged, at: merged.updatedAt });
   357|    return { ok: true, investor: merged, deduped: true };
   358|  }
   359|  const record = buildRecord(input);
   360|  items.push(record);
   361|  await writeJsonFile(INVESTORS_STATE, items);
   362|  await appendEvent({ type: 'create', investor: record, canonical, at: record.createdAt });
   363|  return { ok: true, investor: record, deduped: false };
   364|}
   365|
   366|/** Update an existing investor record. Returns null if not found. */
   367|export async function updateInvestor(id: string, patch: UpdateInvestorInput): Promise<InvestorRecord | null> {
   368|  const items = await readJsonFile<InvestorRecord[]>(INVESTORS_STATE, []);
   369|  const index = items.findIndex((item) => item.id === id);
   370|  if (index === -1) return null;
   371|  const prior = items[index]!;
   372|  const merged = buildRecord({ ...prior, ...patch, source: patch.source ?? prior.source, name: patch.name ?? prior.name }, prior);
   373|  items[index] = merged;
   374|  await writeJsonFile(INVESTORS_STATE, items);
   375|  await appendEvent({ type: 'update', investorId: id, investor: merged, at: merged.updatedAt });
   376|  return merged;
   377|}
   378|
   379|/** Set just the relationship status (pipeline move). Returns null if not found / invalid. */
   380|export async function setInvestorStatus(id: string, status: InvestorStatus): Promise<InvestorRecord | null> {
   381|  if (!VALID_STATUS.has(status)) return null;
   382|  return updateInvestor(id, { status });
   383|}
   384|
   385|/**
   386| * Overwrite the entire investor store in a single durable write. Used by the
   387| * dedup merge migration. Callers must pass the full, already-merged record set.
   388| */
   389|export async function replaceAllInvestors(records: InvestorRecord[]): Promise<void> {
   390|  await writeJsonFile(INVESTORS_STATE, records);
   391|  await appendEvent({ type: 'replace_all', count: records.length, at: nowIso() });
   392|}
   393|
   394|/** Delete an investor record. Returns true if a record was removed. */
   395|export async function deleteInvestor(id: string): Promise<boolean> {
   396|  const items = await readJsonFile<InvestorRecord[]>(INVESTORS_STATE, []);
   397|  const next = items.filter((item) => item.id !== id);
   398|  if (next.length === items.length) return false;
   399|  await writeJsonFile(INVESTORS_STATE, next);
   400|  await appendEvent({ type: 'delete', investorId: id, at: nowIso() });
   401|  return true;
   402|}
   403|
   404|/**
   405| * Bulk-import a batch of records in a single durable write. Each input is
   406| * validated with the same no-fabrication rule as `createInvestor`; invalid
   407| * rows are skipped (never persisted) and reported with their reason, so the
   408| * caller can show an honest imported/skipped count after every import.
   409| */
   410|export async function importInvestors(
   411|  inputs: CreateInvestorInput[],
   412|): Promise<{
   413|  imported: number;
   414|  skipped: number;
   415|  duplicates: number;
   416|  total: number;
   417|  errors: { index: number; name: string; error: string }[];
   418|  duplicateRows: { index: number; name: string; reason: string }[];
   419|  records: InvestorRecord[];
   420|}> {
   421|  const items = await readJsonFile<InvestorRecord[]>(INVESTORS_STATE, []);
   422|  const created: InvestorRecord[] = [];
   423|  const errors: { index: number; name: string; error: string }[] = [];
   424|  const duplicateRows: { index: number; name: string; reason: string }[] = [];
   425|  // Seed the seen-set with existing records so a re-imported list never doubles
   426|  // the CRM, and so duplicate rows WITHIN one import batch collapse to one record.
   427|  const seen = new Set<string>(items.map((r) => investorDedupeKey(r)));
   428|  inputs.forEach((input, index) => {
   429|    const validation = validateCreateInvestor(input);
   430|    if (!validation.ok) {
   431|      errors.push({ index, name: asTrimmedString(input.name), error: validation.error });
   432|      return;
   433|    }
   434|    const key = investorDedupeKey(input);
   435|    if (seen.has(key)) {
   436|      duplicateRows.push({
   437|        index,
   438|        name: asTrimmedString(input.name),
   439|        reason: 'Duplicate of an existing contact (same name + email/phone/company) — skipped, not re-added.',
   440|      });
   441|      return;
   442|    }
   443|    seen.add(key);
   444|    const record = buildRecord(input);
   445|    items.push(record);
   446|    created.push(record);
   447|  });
   448|  if (created.length > 0) {
   449|    await writeJsonFile(INVESTORS_STATE, items);
   450|    await appendEvent({ type: 'import', count: created.length, ids: created.map((r) => r.id), at: nowIso() });
   451|  }
   452|  return {
   453|    imported: created.length,
   454|    skipped: errors.length,
   455|    duplicates: duplicateRows.length,
   456|    total: inputs.length,
   457|    errors,
   458|    duplicateRows,
   459|    records: created,
   460|  };
   461|}
