   474|
   475|/** Read-only roll-up over the CRM for the dashboard header. */
   476|export async function summarizeInvestors(): Promise<InvestorCrmSummary> {
   477|  const items = await readJsonFile<InvestorRecord[]>(INVESTORS_STATE, []);
   478|  const byStatus: Record<InvestorStatus, number> = {
   479|    prospect: 0, contacted: 0, meeting_scheduled: 0, active: 0, invested: 0,
   480|  };
   481|  const bySource: Record<InvestorSource, number> = {
   482|    owner_entered: 0, submitted_form: 0, crm_import: 0, public_source: 0, verified_deal: 0,
   483|  };
   484|  const byPartyType: Record<PartyType, number> = {
   485|    investor: 0, buyer: 0, broker: 0, developer: 0, lender: 0, partner: 0,
   486|  };
   487|  let accredited = 0;
   488|  let leadSum = 0;
   489|  let relSum = 0;
   490|  for (const item of items) {
   491|    byStatus[item.status] = (byStatus[item.status] ?? 0) + 1;
   492|    bySource[item.source] = (bySource[item.source] ?? 0) + 1;
   493|    byPartyType[item.partyType] = (byPartyType[item.partyType] ?? 0) + 1;
   494|    if (item.accreditedStatus === 'accredited') accredited += 1;
   495|    leadSum += item.leadScore;
   496|    relSum += item.relationshipScore;
   497|  }
   498|  const total = items.length;
   499|  return {
   500|    marker: IVX_INVESTOR_CRM_MARKER,
   501|    generatedAt: nowIso(),
   502|    total,
   503|    byStatus,
   504|    bySource,
   505|    byPartyType,
   506|    accredited,
   507|    avgLeadScore: total > 0 ? Math.round(leadSum / total) : 0,
   508|    avgRelationshipScore: total > 0 ? Math.round(relSum / total) : 0,
   509|  };
